import React, { useState, useEffect } from 'react';
import { db } from '../../utils/firebase';
import { doc, getDoc, onSnapshot, collection, query, where, getDocs, addDoc, deleteDoc } from 'firebase/firestore';
import { ArrowUpRight, ArrowDownLeft, Calendar, User, Layers, AlertCircle, Shield, Trash2, PlusCircle, MapPin } from 'lucide-react';

export default function MaterialDept() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [adminId, setAdminId] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(null);
  
  // Dynamic State
  const [assignedArea, setAssignedArea] = useState(''); 
  const [logisticsSector, setLogisticsSector] = useState('');
  const [workersList, setWorkersList] = useState([]);
  const [workerName, setWorkerName] = useState('');
  const [workerLogin, setWorkerLogin] = useState('');
  const [workerPassword, setWorkerPassword] = useState('');

  // 1. Auth Gate: Yahan se data fetch hoke area set hoga
  const handleAdminAuthGate = async (e) => {
    e.preventDefault();
    try {
      const vendorRef = doc(db, "vendors", adminId.trim());
      const vendorSnap = await getDoc(vendorRef);

      if (vendorSnap.exists()) {
        const data = vendorSnap.data();
        if (String(data.password) === String(password)) {
          // DYNAMIC ASSIGNMENT FROM ADMIN HQ
          setAssignedArea(data.targetArea || 'Unassigned');
          setLogisticsSector(data.logisticsSectorType || 'General');
          setIsAuthenticated(true);
        } else {
          setAuthError("Invalid credentials.");
        }
      }
    } catch (err) {
      setAuthError(err.message);
    }
  };

  // 2. Fetch workers based on dynamic area
  useEffect(() => {
    if (isAuthenticated && assignedArea) {
      const fetchWorkers = async () => {
        const q = collection(db, "vendors", assignedArea.trim(), "workers");
        const snap = await getDocs(q);
        setWorkersList(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      };
      fetchWorkers();
    }
  }, [isAuthenticated, assignedArea]);

  // 3. Render
  if (!isAuthenticated) {
    return (
      <div style={{ padding: '50px', textAlign: 'center' }}>
        <form onSubmit={handleAdminAuthGate}>
          <input type="text" placeholder="Admin ID" onChange={(e) => setAdminId(e.target.value)} />
          <input type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} />
          <button type="submit">Login</button>
        </form>
        {authError && <p>{authError}</p>}
      </div>
    );
  }

  return (
    <div style={{ padding: '24px' }}>
      {/* Header with Dynamic Area */}
      <div style={{ display: 'flex', gap: '20px', background: '#0F172A', color: '#fff', padding: '20px', borderRadius: '10px' }}>
        <div>
          <MapPin /> Area: <b>{assignedArea}</b>
        </div>
        <div>
          <Shield /> Sector: <b>{logisticsSector}</b>
        </div>
      </div>

      {/* CRUD Section */}
      <div style={{ marginTop: '20px' }}>
        <h3>Deploy Operators at [{assignedArea}]</h3>
        <input placeholder="Name" value={workerName} onChange={(e) => setWorkerName(e.target.value)} />
        <input placeholder="Login" value={workerLogin} onChange={(e) => setWorkerLogin(e.target.value)} />
        <input placeholder="Password" value={workerPassword} onChange={(e) => setWorkerPassword(e.target.value)} />
        <button onClick={async () => {
          await addDoc(collection(db, "vendors", assignedArea.trim(), "workers"), {
            workerName, loginId: workerLogin, password: workerPassword
          });
          window.location.reload(); // Quick refresh to update list
        }}>Add Worker</button>
      </div>

      {/* Worker List */}
      <div>
        {workersList.map(w => (
          <div key={w.id}> {w.workerName} - {w.loginId} </div>
        ))}
      </div>
    </div>
  );
}
